import os
import secrets
from cryptography.hazmat.primitives.ciphers.aead import AESGCM
from cryptography.hazmat.primitives import hashes
from cryptography.hazmat.primitives.kdf.pbkdf2 import PBKDF2
import base64


class CreditCardEncryption:
    def __init__(self):
        """
        Initialize encryption with key from secure storage.
        Key should be retrieved from environment variable or secure key management service.
        """
        # Retrieve key from environment variable (should be set via secure key management)
        key_material = os.environ.get('ENCRYPTION_KEY_MATERIAL')
        
        if not key_material:
            raise ValueError(
                "ENCRYPTION_KEY_MATERIAL not found in environment. "
                "Please configure secure key management (e.g., AWS KMS, Azure Key Vault, "
                "HashiCorp Vault, or secure environment variables)."
            )
        
        # Derive a proper encryption key from the key material
        kdf = PBKDF2(
            algorithm=hashes.SHA256(),
            length=32,
            salt=b'credit_card_encryption_salt_v1',  # In production, use unique salt per deployment
            iterations=100000,
        )
        self.key = kdf.derive(key_material.encode())
        self.aesgcm = AESGCM(self.key)
    
    def encrypt_credit_card(self, card_number: str) -> str:
        """
        Encrypt credit card number using AES-GCM (authenticated encryption).
        
        Args:
            card_number: Credit card number as string
            
        Returns:
            Base64-encoded encrypted data with nonce prepended
        """
        # Generate cryptographically secure random nonce
        nonce = secrets.token_bytes(12)  # 96-bit nonce for AES-GCM
        
        # Encrypt using authenticated encryption (AES-GCM)
        plaintext = card_number.encode('utf-8')
        ciphertext = self.aesgcm.encrypt(nonce, plaintext, None)
        
        # Prepend nonce to ciphertext and encode as base64 for storage
        encrypted_data = nonce + ciphertext
        return base64.b64encode(encrypted_data).decode('utf-8')
    
    def decrypt_credit_card(self, encrypted_data: str) -> str:
        """
        Decrypt credit card number.
        
        Args:
            encrypted_data: Base64-encoded encrypted data
            
        Returns:
            Decrypted credit card number
        """
        # Decode from base64
        encrypted_bytes = base64.b64decode(encrypted_data.encode('utf-8'))
        
        # Extract nonce and ciphertext
        nonce = encrypted_bytes[:12]
        ciphertext = encrypted_bytes[12:]
        
        # Decrypt and verify authentication tag
        plaintext = self.aesgcm.decrypt(nonce, ciphertext, None)
        return plaintext.decode('utf-8')


